import React from "react";

import { CloseIcon } from "@steez-ui/icons";

import { NotchedViewportFrame } from "./NotchedViewportFrame.js";
import styles from "./RadialMenuOverlay.module.css";

const FULL_CIRCLE_DEGREES = 360;
const JOYSTICK_MAX_RADIUS_RATIO = 0.28;
const JOYSTICK_ACTIVATION_RATIO = 0.34;
const JOYSTICK_COMMIT_RATIO = 0.78;
const EMPTY_ITEMS: readonly RadialMenuItem[] = [];

export interface RadialMenuItem {
  id: string;
  label: string;
  eyebrow: string;
  body: string;
  href?: string;
  shortLabel?: string;
  onSelect?: () => void;
}

export interface RadialMenuOverlayProps {
  open: boolean;
  items: readonly RadialMenuItem[];
  onClose: () => void;
  className?: string;
  title?: React.ReactNode;
  description?: React.ReactNode;
  brand?: React.ReactNode;
  footer?: React.ReactNode;
  contained?: boolean;
  closeLabel?: string;
  ariaLabel?: string;
}

export function RadialMenuOverlay({
  open,
  items,
  onClose,
  className = "",
  title = "Navigate the runtime",
  description = "One radial control surface for the sections that matter most.",
  brand,
  footer,
  contained = false,
  closeLabel = "Close navigation",
  ariaLabel = "Site navigation",
}: RadialMenuOverlayProps) {
  const safeItems = items.length > 0 ? items : EMPTY_ITEMS;
  const [isPending, startTransition] = React.useTransition();
  const [activeId, setActiveId] = React.useState(safeItems[0]?.id ?? "");
  const [isDragging, setIsDragging] = React.useState(false);
  const [stickOffset, setStickOffset] = React.useState({ x: 0, y: 0 });
  const wheelRef = React.useRef<HTMLDivElement | null>(null);
  const activeIdRef = React.useRef(activeId);
  const dragPointerIdRef = React.useRef<number | null>(null);
  const itemsRef = React.useRef(items);
  const onCloseRef = React.useRef(onClose);

  itemsRef.current = items;
  onCloseRef.current = onClose;

  React.useEffect(() => {
    activeIdRef.current = activeId;
  }, [activeId]);

  React.useEffect(() => {
    if (!open) {
      return undefined;
    }

    setActiveId(safeItems[0]?.id ?? "");
    setStickOffset({ x: 0, y: 0 });
    setIsDragging(false);
    dragPointerIdRef.current = null;
    return undefined;
  }, [open, safeItems]);

  React.useEffect(() => {
    if (!open || typeof window === "undefined") {
      return undefined;
    }

    const previousOverflow = document.body.style.overflow;
    document.body.style.overflow = "hidden";

    const onKeyDown = (event: KeyboardEvent) => {
      if (event.key === "Escape") {
        onClose();
      }
    };

    window.addEventListener("keydown", onKeyDown);
    return () => {
      document.body.style.overflow = previousOverflow;
      window.removeEventListener("keydown", onKeyDown);
    };
  }, [onClose, open]);

  const getClosestItem = React.useCallback((angle: number) => {
    const currentItems = itemsRef.current;
    const firstItem = currentItems[0];

    if (!firstItem) {
      return undefined;
    }

    let closest = firstItem;
    let closestDistance = Number.POSITIVE_INFINITY;

    currentItems.forEach((item, index) => {
      const itemAngle =
        -90 + (FULL_CIRCLE_DEGREES / Math.max(currentItems.length, 1)) * index;
      const normalizedDistance = Math.abs(
        ((((angle - itemAngle) % FULL_CIRCLE_DEGREES) + 540) % FULL_CIRCLE_DEGREES) - 180,
      );

      if (normalizedDistance < closestDistance) {
        closest = item;
        closestDistance = normalizedDistance;
      }
    });

    return closest;
  }, []);

  const resetStick = React.useCallback(() => {
    dragPointerIdRef.current = null;
    setIsDragging(false);
    setStickOffset({ x: 0, y: 0 });
  }, []);

  const triggerItem = React.useCallback((item: RadialMenuItem) => {
    item.onSelect?.();

    if (item.href && typeof window !== "undefined") {
      if (item.href.startsWith("#")) {
        const target = document.querySelector<HTMLElement>(item.href);
        if (target) {
          target.scrollIntoView({ behavior: "smooth", block: "start" });
        } else {
          window.location.hash = item.href;
        }
      } else {
        window.location.assign(item.href);
      }
    }

    onCloseRef.current();
  }, []);

  const updateStickFromPointer = React.useCallback(
    (clientX: number, clientY: number) => {
      const wheel = wheelRef.current;
      if (!wheel) {
        return 0;
      }

      const rect = wheel.getBoundingClientRect();
      const centerX = rect.left + rect.width / 2;
      const centerY = rect.top + rect.height / 2;
      const deltaX = clientX - centerX;
      const deltaY = clientY - centerY;
      const distance = Math.hypot(deltaX, deltaY);
      const maxDistance = Math.min(rect.width, rect.height) * JOYSTICK_MAX_RADIUS_RATIO;
      const clampRatio = distance > maxDistance && distance > 0 ? maxDistance / distance : 1;
      const x = deltaX * clampRatio;
      const y = deltaY * clampRatio;
      const normalizedDistance = maxDistance > 0 ? distance / maxDistance : 0;

      setStickOffset({ x, y });

      if (normalizedDistance >= JOYSTICK_ACTIVATION_RATIO) {
        const nextItem = getClosestItem((Math.atan2(y, x) * 180) / Math.PI);
        if (nextItem && nextItem.id !== activeIdRef.current) {
          activeIdRef.current = nextItem.id;
          startTransition(() => {
            setActiveId(nextItem.id);
          });
        }
      }

      return normalizedDistance;
    },
    [getClosestItem],
  );

  React.useEffect(() => {
    if (!isDragging || typeof window === "undefined") {
      return undefined;
    }

    const handlePointerMove = (event: PointerEvent) => {
      if (dragPointerIdRef.current !== null && event.pointerId !== dragPointerIdRef.current) {
        return;
      }

      updateStickFromPointer(event.clientX, event.clientY);
    };

    const handlePointerEnd = (event: PointerEvent) => {
      if (dragPointerIdRef.current !== null && event.pointerId !== dragPointerIdRef.current) {
        return;
      }

      const progress = updateStickFromPointer(event.clientX, event.clientY);
      const selectedItem =
        itemsRef.current.find((item) => item.id === activeIdRef.current) ?? itemsRef.current[0];

      resetStick();

      if (progress >= JOYSTICK_COMMIT_RATIO && selectedItem) {
        triggerItem(selectedItem);
      }
    };

    window.addEventListener("pointermove", handlePointerMove, { passive: true });
    window.addEventListener("pointerup", handlePointerEnd);
    window.addEventListener("pointercancel", handlePointerEnd);

    return () => {
      window.removeEventListener("pointermove", handlePointerMove);
      window.removeEventListener("pointerup", handlePointerEnd);
      window.removeEventListener("pointercancel", handlePointerEnd);
    };
  }, [isDragging, resetStick, triggerItem, updateStickFromPointer]);

  if (!open || safeItems.length === 0) {
    return null;
  }

  const activeItem = safeItems.find((item) => item.id === activeId) ?? safeItems[0];
  const activeIndex = Math.max(
    0,
    safeItems.findIndex((item) => item.id === activeItem.id),
  );
  const angleStep = FULL_CIRCLE_DEGREES / Math.max(safeItems.length, 1);
  const stickLength = Math.hypot(stickOffset.x, stickOffset.y);
  const stickAngle = Math.atan2(stickOffset.y, stickOffset.x);

  return (
    <div
      className={`${styles.overlay} ${contained ? styles.contained : ""} ${className}`.trim()}
      role="dialog"
      aria-modal={contained ? undefined : "true"}
      aria-label={ariaLabel}
    >
      <button
        type="button"
        className={styles.backdrop}
        aria-label={closeLabel}
        onClick={onClose}
      />
      <div className={styles.panel}>
        <NotchedViewportFrame className={styles.frame} tone="strong" />
        <div className={styles.chrome}>
          <div className={styles.header}>
            <div className={styles.headerBlock}>
              <div className={styles.headerKicker}>Navigation</div>
              {brand ? <div className={styles.brand}>{brand}</div> : null}
            </div>
            <button
              type="button"
              className={styles.closeButton}
              onClick={onClose}
              aria-label={closeLabel}
              title={closeLabel}
            >
              <CloseIcon width={16} height={16} />
            </button>
          </div>

          <div className={styles.layout}>
            <div className={styles.copy}>
              <div className={styles.copyEyebrow}>{activeItem.eyebrow}</div>
              <h2 className={styles.copyTitle}>{title}</h2>
              <p className={styles.copyBody}>{description}</p>

              <div className={styles.detailPanel}>
                <div className={styles.detailMeta}>
                  {String(activeIndex + 1).padStart(2, "0")} /{" "}
                  {String(safeItems.length).padStart(2, "0")}
                </div>
                <div className={styles.detailTitle}>{activeItem.label}</div>
                <p className={styles.detailBody}>{activeItem.body}</p>
                <button
                  type="button"
                  className={styles.detailLink}
                  onClick={() => triggerItem(activeItem)}
                >
                  Open section
                </button>
              </div>
            </div>

            <div className={styles.wheelWrap}>
              <div ref={wheelRef} className={styles.wheel}>
                <div className={styles.outerRing} aria-hidden="true" />
                <div className={styles.innerRing} aria-hidden="true" />
                <div className={styles.axisHorizontal} aria-hidden="true" />
                <div className={styles.axisVertical} aria-hidden="true" />

                {safeItems.map((item, index) => {
                  const angle = -90 + angleStep * index;
                  const isActive = item.id === activeItem.id;

                  return (
                    <button
                      type="button"
                      key={item.id}
                      className={`${styles.node} ${isActive ? styles.nodeActive : ""}`}
                      style={
                        {
                          "--wheel-angle": `${angle}deg`,
                        } as React.CSSProperties
                      }
                      onMouseEnter={() => {
                        if (!isDragging) {
                          setActiveId(item.id);
                        }
                      }}
                      onFocus={() => setActiveId(item.id)}
                      onClick={() => {
                        setActiveId(item.id);
                        triggerItem(item);
                      }}
                      aria-current={isActive ? "true" : undefined}
                    >
                      <span className={styles.nodeConnector} aria-hidden="true" />
                      <span className={styles.nodeMarker}>
                        {item.shortLabel ?? String(index + 1).padStart(2, "0")}
                      </span>
                      <span className={styles.nodeLabel}>{item.label}</span>
                    </button>
                  );
                })}

                <div className={styles.core} aria-hidden="true" />
                <div
                  className={styles.stickZone}
                  onPointerDown={(event) => {
                    dragPointerIdRef.current = event.pointerId;
                    setIsDragging(true);
                    updateStickFromPointer(event.clientX, event.clientY);
                  }}
                >
                  <div
                    className={styles.stickStem}
                    style={
                      {
                        "--stick-angle": `${stickAngle}rad`,
                        "--stick-length": `${stickLength}px`,
                      } as React.CSSProperties
                    }
                    aria-hidden="true"
                  />
                  <div
                    className={`${styles.stickKnob} ${isDragging ? styles.stickKnobDragging : ""} ${
                      isPending ? styles.stickKnobPending : ""
                    }`}
                    style={
                      {
                        "--stick-x": `${stickOffset.x}px`,
                        "--stick-y": `${stickOffset.y}px`,
                      } as React.CSSProperties
                    }
                    aria-hidden="true"
                  />
                </div>
              </div>
            </div>
          </div>

          <div className={styles.footer}>
            <div className={styles.footerHint}>Press Esc to close</div>
            {footer ? <div className={styles.footerContent}>{footer}</div> : null}
          </div>
        </div>
      </div>
    </div>
  );
}

export default RadialMenuOverlay;

.overlay {
  position: fixed;
  inset: 0;
  z-index: 120;
  display: grid;
  padding: 1rem;
}

.contained {
  position: absolute;
}

.backdrop {
  position: absolute;
  inset: 0;
  padding: 0;
  border: 0;
  background: color-mix(in srgb, var(--bg-primary) 76%, transparent);
  backdrop-filter: blur(10px);
  cursor: pointer;
}

.contained .backdrop {
  background: color-mix(in srgb, var(--bg-primary) 18%, transparent);
}

.panel {
  position: relative;
  min-height: 100%;
  background: color-mix(in srgb, var(--bg-primary) 99%, transparent);
  overflow: hidden;
}

.frame {
  inset: 0;
}

.chrome {
  position: relative;
  z-index: 1;
  display: grid;
  grid-template-rows: auto 1fr auto;
  min-height: 100%;
  padding: clamp(2.1rem, 3vw, 3rem) clamp(2.1rem, 4vw, 3.8rem)
    clamp(2rem, 3vw, 2.6rem);
  gap: 1.35rem;
  animation: overlayBootBlink 420ms steps(2, end) 3;
}

.header,
.footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
}

.headerBlock {
  display: grid;
  gap: 0.28rem;
}

.headerKicker,
.copyEyebrow,
.detailMeta,
.detailLink,
.coreKicker,
.coreMeta,
.nodeLabel,
.footerHint {
  color: var(--text-secondary);
  font-family: var(--font-mono);
  font-size: 0.72rem;
  letter-spacing: 0.16em;
  text-transform: uppercase;
}

.brand {
  color: var(--text-primary);
  font-family: var(--font-primary);
  font-size: 0.95rem;
  line-height: 1.2;
}

.closeButton {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 2.4rem;
  height: 2.4rem;
  padding: 0;
  border: 1px solid color-mix(in srgb, var(--border-color) 78%, transparent);
  background: color-mix(in srgb, var(--bg-primary) 96%, transparent);
  color: var(--text-primary);
  cursor: pointer;
}

.layout {
  display: grid;
  grid-template-columns: minmax(18rem, 0.92fr) minmax(22rem, 1.08fr);
  gap: clamp(1.6rem, 4vw, 4rem);
  align-items: center;
  min-height: 0;
}

.copy {
  display: grid;
  gap: 0.72rem;
  align-content: start;
  max-width: 24rem;
}

.copyTitle,
.detailTitle,
.coreTitle {
  color: var(--text-primary);
  margin: 0;
}

.copyTitle {
  font-family: var(--font-display);
  font-size: clamp(2.25rem, 4vw, 4rem);
  font-weight: 400;
  line-height: 0.92;
  letter-spacing: 0.04em;
  text-transform: uppercase;
}

.copyBody,
.detailBody {
  margin: 0;
  color: var(--text-secondary);
  line-height: 1.58;
}

.detailPanel {
  display: grid;
  gap: 0.5rem;
  margin-top: 1rem;
  padding-top: 1.2rem;
  border-top: 1px solid color-mix(in srgb, var(--border-color) 74%, transparent);
}

.detailTitle {
  font-family: var(--font-primary);
  font-size: clamp(1.4rem, 1.1rem + 0.7vw, 1.9rem);
  font-weight: 600;
  letter-spacing: -0.03em;
}

.detailLink {
  display: inline-flex;
  align-items: center;
  width: fit-content;
  min-height: 2rem;
  padding: 0;
  border: 0;
  background: none;
  color: var(--text-primary);
  cursor: pointer;
}

.detailLink:hover {
  color: var(--text-secondary);
}

.wheelWrap {
  display: grid;
  place-items: center;
}

.wheel {
  position: relative;
  width: min(100%, 32rem);
  aspect-ratio: 1;
  --wheel-accent: color-mix(in srgb, var(--accent-primary, var(--text-primary)) 84%, white 8%);
  --wheel-accent-soft: color-mix(
    in srgb,
    var(--accent-primary, var(--text-primary)) 28%,
    transparent
  );
  filter: drop-shadow(0 0 20px color-mix(in srgb, var(--wheel-accent) 12%, transparent));
}

.outerRing,
.innerRing,
.axisHorizontal,
.axisVertical {
  position: absolute;
  inset: 50%;
  translate: -50% -50%;
  pointer-events: none;
}

.outerRing,
.innerRing {
  border-radius: 50%;
}

.outerRing {
  width: 100%;
  height: 100%;
  border: 1px solid color-mix(in srgb, var(--wheel-accent) 24%, transparent);
  animation: orbitSpinClockwise 18s linear infinite;
}

.innerRing {
  width: 58%;
  height: 58%;
  border: 1px solid color-mix(in srgb, var(--wheel-accent) 18%, transparent);
  animation: orbitSpinCounter 13s linear infinite;
}

.outerRing::before,
.outerRing::after,
.innerRing::before,
.innerRing::after {
  content: "";
  position: absolute;
  inset: 0;
  border-radius: inherit;
}

.outerRing::before {
  inset: 0.65rem;
  border: 1px dashed color-mix(in srgb, var(--wheel-accent) 30%, transparent);
  opacity: 0.78;
}

.outerRing::after {
  inset: 0.9rem;
  background:
    conic-gradient(
      from 110deg,
      transparent 0deg 38deg,
      color-mix(in srgb, var(--wheel-accent) 64%, transparent) 38deg 66deg,
      transparent 66deg 168deg,
      color-mix(in srgb, var(--wheel-accent) 42%, transparent) 168deg 194deg,
      transparent 194deg 274deg,
      color-mix(in srgb, var(--wheel-accent) 74%, transparent) 274deg 308deg,
      transparent 308deg 360deg
    );
  -webkit-mask: radial-gradient(farthest-side, transparent calc(100% - 2px), #000 calc(100% - 1px));
  mask: radial-gradient(farthest-side, transparent calc(100% - 2px), #000 calc(100% - 1px));
  opacity: 0.9;
  animation: orbitSpinCounter 7.5s linear infinite;
}

.innerRing::before {
  inset: 0.55rem;
  border: 1px dashed color-mix(in srgb, var(--wheel-accent) 24%, transparent);
  opacity: 0.72;
}

.innerRing::after {
  inset: 0.7rem;
  background:
    conic-gradient(
      from -70deg,
      transparent 0deg 48deg,
      color-mix(in srgb, var(--wheel-accent) 56%, transparent) 48deg 82deg,
      transparent 82deg 210deg,
      color-mix(in srgb, var(--wheel-accent) 48%, transparent) 210deg 238deg,
      transparent 238deg 360deg
    );
  -webkit-mask: radial-gradient(farthest-side, transparent calc(100% - 2px), #000 calc(100% - 1px));
  mask: radial-gradient(farthest-side, transparent calc(100% - 2px), #000 calc(100% - 1px));
  opacity: 0.76;
  animation: orbitSpinClockwise 8.5s linear infinite;
}

.axisHorizontal,
.axisVertical {
  background: color-mix(in srgb, var(--wheel-accent) 30%, transparent);
  box-shadow: 0 0 14px color-mix(in srgb, var(--wheel-accent) 12%, transparent);
  animation: axisPulse 4.2s ease-in-out infinite;
}

.axisHorizontal {
  width: 74%;
  height: 1px;
}

.axisVertical {
  width: 1px;
  height: 74%;
}

.core {
  position: absolute;
  inset: 50%;
  translate: -50% -50%;
  width: 9.4rem;
  height: 9.4rem;
  z-index: 1;
  border-radius: 50%;
  border: 1px solid color-mix(in srgb, var(--wheel-accent) 30%, transparent);
  background:
    radial-gradient(
      circle at 35% 30%,
      color-mix(in srgb, white 30%, transparent) 0%,
      transparent 32%
    ),
    radial-gradient(
      circle at 50% 50%,
      color-mix(in srgb, var(--wheel-accent) 14%, var(--bg-primary)) 0%,
      color-mix(in srgb, var(--bg-primary) 96%, black) 100%
    );
  box-shadow:
    inset 0 0 0 1px color-mix(in srgb, var(--wheel-accent) 14%, transparent),
    0 0 26px color-mix(in srgb, var(--wheel-accent) 10%, transparent);
}

.core::before,
.core::after {
  content: "";
  position: absolute;
  inset: 50%;
  translate: -50% -50%;
  border-radius: 50%;
}

.core::before {
  width: 74%;
  height: 74%;
  border: 1px solid color-mix(in srgb, var(--wheel-accent) 26%, transparent);
  opacity: 0.9;
}

.core::after {
  width: 22%;
  height: 22%;
  background: color-mix(in srgb, var(--wheel-accent) 46%, var(--bg-primary));
  box-shadow: 0 0 18px color-mix(in srgb, var(--wheel-accent) 16%, transparent);
}

.node {
  position: absolute;
  top: 50%;
  left: 50%;
  display: grid;
  justify-items: center;
  gap: 0.45rem;
  width: max-content;
  padding: 0;
  border: 0;
  background: none;
  color: inherit;
  cursor: pointer;
  transform:
    translate(-50%, -50%)
    rotate(var(--wheel-angle))
    translateY(-12rem)
    rotate(calc(var(--wheel-angle) * -1));
  transition: transform 180ms ease, color 180ms ease;
}

.node:hover,
.node:focus-visible,
.nodeActive {
  transform:
    translate(-50%, -50%)
    rotate(var(--wheel-angle))
    translateY(-12.35rem)
    rotate(calc(var(--wheel-angle) * -1));
}

.nodeConnector {
  width: 1px;
  height: 1.3rem;
  background: color-mix(in srgb, var(--wheel-accent) 26%, transparent);
}

.nodeMarker {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 3.15rem;
  height: 3.15rem;
  border-radius: 999px;
  border: 1px solid color-mix(in srgb, var(--wheel-accent) 28%, transparent);
  background:
    radial-gradient(
      circle at 34% 28%,
      color-mix(in srgb, white 24%, transparent) 0%,
      transparent 30%
    ),
    color-mix(in srgb, var(--bg-primary) 97%, transparent);
  color: var(--text-primary);
  font-family: var(--font-mono);
  font-size: 0.78rem;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  box-shadow: 0 0 18px color-mix(in srgb, var(--wheel-accent) 8%, transparent);
}

.nodeLabel {
  color: var(--text-primary);
  text-align: center;
}

.node:hover .nodeMarker,
.node:focus-visible .nodeMarker,
.nodeActive .nodeMarker {
  background: color-mix(in srgb, var(--wheel-accent) 94%, white 6%);
  color: var(--bg-primary);
  box-shadow:
    0 0 0 1px color-mix(in srgb, var(--bg-primary) 84%, transparent),
    0 0 20px color-mix(in srgb, var(--wheel-accent) 20%, transparent);
}

.stickZone {
  position: absolute;
  inset: 50%;
  z-index: 2;
  width: 48%;
  height: 48%;
  translate: -50% -50%;
  border-radius: 50%;
  touch-action: none;
}

.stickStem {
  position: absolute;
  top: 50%;
  left: 50%;
  width: max(var(--stick-length), 0px);
  height: 2px;
  border-radius: 999px;
  background:
    linear-gradient(
      90deg,
      color-mix(in srgb, var(--wheel-accent) 12%, transparent) 0%,
      color-mix(in srgb, var(--wheel-accent) 70%, transparent) 100%
    );
  transform-origin: left center;
  transform: rotate(var(--stick-angle));
  box-shadow: 0 0 12px color-mix(in srgb, var(--wheel-accent) 14%, transparent);
}

.stickKnob {
  position: absolute;
  top: 50%;
  left: 50%;
  width: 3.45rem;
  height: 3.45rem;
  translate: calc(-50% + var(--stick-x, 0px)) calc(-50% + var(--stick-y, 0px));
  border-radius: 50%;
  border: 1px solid color-mix(in srgb, var(--wheel-accent) 78%, transparent);
  background:
    radial-gradient(
      circle at 34% 30%,
      color-mix(in srgb, white 34%, transparent) 0%,
      transparent 28%
    ),
    radial-gradient(
      circle at 50% 50%,
      color-mix(in srgb, var(--wheel-accent) 76%, white 6%) 0%,
      color-mix(in srgb, var(--wheel-accent) 48%, var(--bg-primary)) 58%,
      color-mix(in srgb, var(--bg-primary) 92%, black) 100%
    );
  box-shadow:
    0 0 0 1px color-mix(in srgb, var(--bg-primary) 84%, transparent),
    0 12px 26px rgba(0, 0, 0, 0.18),
    0 0 24px color-mix(in srgb, var(--wheel-accent) 18%, transparent);
  transition:
    translate 160ms ease,
    border-color 160ms ease,
    background 160ms ease,
    transform 160ms ease;
}

.stickKnob::before,
.stickKnob::after {
  content: "";
  position: absolute;
  inset: 50%;
  translate: -50% -50%;
  background: color-mix(in srgb, var(--bg-primary) 88%, transparent);
}

.stickKnob::before {
  width: 42%;
  height: 1px;
}

.stickKnob::after {
  width: 1px;
  height: 42%;
}

.stickKnobDragging,
.stickKnobPending {
  border-color: color-mix(in srgb, var(--wheel-accent) 96%, transparent);
}

.stickKnobDragging {
  transform: scale(1.04);
}

.footer {
